const crypto = require('crypto');

for (const item of $input.all()) {
  if (item.binary) {
    // Find the first binary data field (could be 'data', 'file', or any other name)
    const binaryKey = Object.keys(item.binary)[0];

    if (binaryKey && item.binary[binaryKey]) {
      const timestamp = Date.now();
      const random = crypto.randomBytes(4).toString('hex');
      const filePrefix = `${timestamp}_${random}_`;

      const fileName = item.binary[binaryKey].fileName || 'upload';
      const fileExt = fileName.split('.').pop().toLowerCase();

      // Normalize to 'data' field for consistent downstream processing
      if (binaryKey !== 'data') {
        item.binary.data = item.binary[binaryKey];
        delete item.binary[binaryKey];
      }

      // Set binary.data.fileName to include the prefix
      const prefixedFileName = `${filePrefix}input.${fileExt}`;
      item.binary.data.fileName = prefixedFileName;

      // Store metadata in json
      item.json.filePrefix = filePrefix;
      item.json.fileExtension = fileExt;
      item.json.originalFileName = fileName;
      item.json.timestamp = timestamp;
    }
  }
}

return $input.all();

// Parse excel_extractor.py stdout → Workflow A output contract
const item = $input.all()[0];
const exitCode = item.json.exitCode ?? 0;
const rawOut  = (item.json.stdout || '').trim();
const rawErr  = (item.json.stderr || '').trim();

let extracted;
try {
  extracted = JSON.parse(rawOut);
} catch (e) {
  // stdout wasn't valid JSON — surface stderr as the error message
  return [{ json: {
    error: rawErr || `excel_extractor.py output was not valid JSON: ${rawOut.substring(0, 300)}`,
    errorCode: 'EXCEL_PARSE_FAILED',
    originalFileName: $node["Set Binary Filename"].json.originalFileName
  }}];
}

// If the extractor itself returned an error object, pass it through
if (extracted.error) {
  return [{ json: extracted }];
}

// Normalise to Workflow A output contract
return [{ json: {
  filePrefix:       extracted.filePrefix,
  originalFileName: extracted.originalFileName,
  totalPages:       extracted.totalPages,
  totalWords:       extracted.totalWords,
  hasDiagrams:      false,
  fullDocument:     extracted.fullDocument,
  pages:            extracted.pages,
  metadata:         extracted.metadata
}}];

const stdout = $input.all()[0].json.stdout || '';
if (!stdout.trim()) {
  throw new Error('No images generated from PDF - pdftoppm produced no output');
}
const files = stdout.split('\n').filter(f => f.trim() !== '');
const filePrefix = $('Set Binary Filename').all()[0].json.filePrefix;
const originalFileName = $('Set Binary Filename').all()[0].json.originalFileName;

return files.map((filePath, index) => {
  const fileName = filePath.split('/').pop();
  return {
    json: {
      pageNumber: index + 1,
      fileName: fileName,
      filePath: filePath,
      originalFile: originalFileName,
      filePrefix: filePrefix
    }
  };
});

const items = $input.all();
const results = [];

const visionItems = $('Florence Vision Analysis').all();
const metaItems = $('Prepare Generated File List').all();

for (let i = 0; i < items.length; i++) {
  const visionText = visionItems[i]?.json?.stdout || '';
  const meta = metaItems[i]?.json || {};

  let visionData = {};
  let ocrText = '';
  let description = '';
  try {
    visionData = JSON.parse(visionText);
    ocrText = visionData.ocr_text || '';
    description = visionData.description || '';
  } catch (e) {
    ocrText = visionText;
    visionData = { raw: visionText };
  }

  // Use OCR text for actual content, fall back to description
  const text = ocrText || description;
  const wordCount = text.split(/\s+/).length;
  // If OCR returns very few words, it is likely a diagram/image
  const ocrWordCount = ocrText.split(/\s+/).length;
  const complexityScore = (ocrWordCount < 30) ? 0.8 : 0.2;

  results.push({
    json: {
      ...meta,
      extractedText: text,
      visionAnalysis: { description: description },
      wordCount,
      complexityScore,
      isDiagram: complexityScore > 0.5
    }
  });
}

return results;

const pages = $input.all();
const filePrefix = pages[0]?.json?.filePrefix || 'unknown';
const originalFile = pages[0]?.json?.originalFile || 'unknown';

const fullText = pages.map(p => p.json.extractedText).join('\n\n');
const totalWords = pages.reduce((sum, p) => sum + p.json.wordCount, 0);
const hasDiagrams = pages.some(p => p.json.isDiagram);

const result = {
  filePrefix,
  originalFileName: originalFile,
  totalPages: pages.length,
  totalWords,
  hasDiagrams,
  fullDocument: fullText,
  pages: pages.map(p => ({
    pageNumber: p.json.pageNumber,
    text: p.json.extractedText,
    wordCount: p.json.wordCount,
    visionAnalysis: p.json.visionAnalysis,
    isDiagram: p.json.isDiagram
  }))
};

return [{ json: result }];

const crypto = require('crypto');
const https = require('https');

// Parse credentials from connection string (mirrors blobstorage.js approach)
const connectionString = $env.AZURE_STORAGE_CONNECTION_STRING || $env.AZURE_BLOB_CONNECTION_STRING;
let accountName, accountKey;
if (connectionString) {
  accountName = connectionString.match(/AccountName=([^;]+)/)?.[1];
  accountKey  = connectionString.match(/AccountKey=([^;]+)/)?.[1];
}
// Fallback to individual env vars if connection string not set
if (!accountName) accountName = $env.AZURE_STORAGE_ACCOUNT_NAME || 'unificdmpblob';
if (!accountKey)  accountKey  = $env.AZURE_STORAGE_ACCOUNT_KEY;

if (!accountKey) {
  throw new Error(
    'Azure credentials not found. Set AZURE_STORAGE_CONNECTION_STRING ' +
    '(e.g. "DefaultEndpointsProtocol=https;AccountName=...;AccountKey=...;EndpointSuffix=core.windows.net") ' +
    'in the n8n container environment.'
  );
}

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    https.get(url, (res) => {
      const chunks = [];
      res.on('data', chunk => chunks.push(chunk));
      res.on('end', () => resolve({
        buffer: Buffer.concat(chunks),
        statusCode: res.statusCode,
        contentType: res.headers['content-type'] || 'application/octet-stream'
      }));
      res.on('error', reject);
    }).on('error', reject);
  });
}

function generateSasUrl(container, blobPath, sr = 'b', permissions = 'r') {
  const now = new Date();
  const expiry = new Date(now.getTime() + 3600000); // 1 hour
  const sv = '2020-12-06';
  const fmt = (d) => d.toISOString().replace(/\.\d{3}Z$/, 'Z');
  const st = fmt(now);
  const se = fmt(expiry);
  const canonicalizedResource = `/blob/${accountName}/${container}/${blobPath}`;
  // sv=2020-12-06: 16 fields, 15 \n, NO trailing newline (signedEncryptionScope added)
  const stringToSign = [permissions, st, se, canonicalizedResource, '', '', 'https', sv, sr, '', '', '', '', '', '', ''].join('\n');
  const key = Buffer.from(accountKey, 'base64');
  const sig = crypto.createHmac('sha256', key).update(Buffer.from(stringToSign, 'utf8')).digest('base64');
  // Build query string manually — URLSearchParams is not available in the n8n task runner VM sandbox
  const qs = 'sv='  + encodeURIComponent(sv)
           + '&sr=b'
           + '&sp=r'
           + '&st='  + encodeURIComponent(st)
           + '&se='  + encodeURIComponent(se)
           + '&spr=https'
           + '&sig=' + encodeURIComponent(sig);
  return `https://${accountName}.blob.core.windows.net/${container}/${blobPath}?${qs}`;
}

async function fetchBlob(container, blobPath) {
  const sasUrl = generateSasUrl(container, blobPath);
  const { buffer, statusCode, contentType } = await httpsGet(sasUrl);
  if (statusCode !== 200) {
    throw new Error(`Azure Blob download failed HTTP ${statusCode} for ${container}/${blobPath}. Body: ${buffer.toString().substring(0, 300)}`);
  }
  return { buffer, contentType };
}

const items = $input.all();
const result = [];

for (const item of items) {
  // Pass through if binary already present (direct file upload path)
  if (item.binary && Object.keys(item.binary).length > 0) {
    result.push(item);
    continue;
  }

  // Normalize: test webhook wraps body under item.json.body; production uses item.json directly
  const bodyData  = item.json.body || item.json;
  const blobPath  = bodyData.blobPath;
  const blobFiles = bodyData.blobFiles;

  if (!blobPath && !blobFiles) {
    result.push(item);
    continue;
  }

  if (!item.binary) item.binary = {};

  if (blobPath) {
    // Single-file mode: { "blobPath": "folder/file.pdf", "azureContainer": "compliance" }
    const container = bodyData.azureContainer || 'compliance';
    const { buffer, contentType } = await fetchBlob(container, blobPath);
    const fileName = blobPath.split('/').pop();
    item.binary.data = await this.helpers.prepareBinaryData(buffer, fileName, contentType);
    item.json.azureBlobFetched = true;
    item.json.originalFileName = fileName;
  }

  if (blobFiles) {
    // Multi-file mode: { "file0": "path.pdf" } or { "file0": { "blobPath": "...", "container": "..." } }
    for (const [fieldName, blobInfo] of Object.entries(blobFiles)) {
      const bp = typeof blobInfo === 'string' ? blobInfo : blobInfo.blobPath;
      const container = (typeof blobInfo === 'object' && blobInfo.container)
        ? blobInfo.container
        : (item.json.azureContainer || 'compliance');
      const { buffer, contentType } = await fetchBlob(container, bp);
      const fileName = bp.split('/').pop();
      item.binary[fieldName] = await this.helpers.prepareBinaryData(buffer, fileName, contentType);
    }
    item.json.azureBlobFetched = true;
  }

  result.push(item);
}

return result;

